"use client";

import { useState } from "react";
import { cn } from "@/lib/utils";
import { useYtcnPlayer } from "@/registry/new-york/player/use-ytcn-player";
import { useKeyboardShortcuts } from "@/registry/new-york/player/use-keyboard-shortcuts";
import type {
  YtcnPlayerOptions,
  KeyboardBindings,
} from "@/registry/new-york/player/types";
import { YtcnControls } from "@/registry/new-york/player/ytcn-controls";
import { YtcnOverlay } from "@/registry/new-york/player/ytcn-overlay";
import { YtcnLoader } from "@/registry/new-york/player/ytcn-loader";

interface YtcnPlayerProps extends YtcnPlayerOptions {
  /** Enable built-in keyboard shortcuts (default: true) */
  keyboardShortcuts?: boolean;
  /** Override default keyboard bindings */
  keyboardBindings?: KeyboardBindings;
  /** Additional CSS class for the outer container */
  className?: string;
}

/**
 * YtcnPlayer — Top-level composed YouTube player.
 *
 * Assembles the iframe, overlay, controls, and loader into a single
 * drop-in component. For full customisation, use the `useYtcnPlayer`
 * hook directly and compose your own UI.
 *
 * Controls are hidden by default and appear on hover (via CSS group).
 * In fullscreen mode the container fills the viewport.
 */
export function YtcnPlayer({
  videoId,
  autoplay = false,
  defaultQuality = "auto",
  defaultSpeed = 1,
  startAt = 0,
  onEnd,
  onTimeUpdate,
  onQualityChange,
  onPlaybackRateChange,
  keyboardShortcuts = true,
  keyboardBindings,
  className,
}: YtcnPlayerProps) {
  const { containerRef, playerDivRef, state, controls } = useYtcnPlayer({
    videoId,
    autoplay,
    defaultQuality,
    defaultSpeed,
    startAt,
    onEnd,
    onTimeUpdate,
    onQualityChange,
    onPlaybackRateChange,
  });

  // Controls visibility — show on hover or when dragging the timeline
  const [isHovering, setIsHovering] = useState(false);
  const controlsVisible = isHovering || !state.isPlaying;

  // Keyboard shortcuts
  useKeyboardShortcuts({
    enabled: keyboardShortcuts,
    onPlay: controls.togglePlay,
    onMute: controls.toggleMute,
    onFullscreen: controls.toggleFullscreen,
    onSeekBack: () => controls.seekRelative(-10),
    onSeekForward: () => controls.seekRelative(10),
    bindings: keyboardBindings,
  });

  return (
    <div
      ref={containerRef}
      className={cn(
        "relative w-full bg-black select-none group overflow-hidden",
        state.isFullscreen
          ? "fixed inset-0 z-50"
          : "aspect-video rounded-lg border shadow-lg",
        className
      )}
      onMouseEnter={() => setIsHovering(true)}
      onMouseLeave={() => setIsHovering(false)}
      onMouseMove={() => {
        if (!isHovering) setIsHovering(true);
      }}
    >
      {/* Loading overlay */}
      <YtcnLoader isLoading={state.isLoading} />

      {/* YouTube player mount point */}
      <div className="absolute inset-0 overflow-hidden">
        <div ref={playerDivRef} className="w-full h-full" />
      </div>

      {/* Click overlay for play/pause */}
      <YtcnOverlay onClick={controls.togglePlay} />

      {/* Controls bar */}
      <YtcnControls
        state={state}
        onTogglePlay={controls.togglePlay}
        onSeek={controls.seekTo}
        onVolumeChange={controls.setVolume}
        onToggleMute={controls.toggleMute}
        onSpeedChange={controls.setSpeed}
        onQualityChange={controls.setQuality}
        onToggleFullscreen={controls.toggleFullscreen}
        visible={controlsVisible}
        containerRef={containerRef}
      />
    </div>
  );
}

"use client";

import {
  IconPlayerPlayFilled,
  IconPlayerPauseFilled,
} from "@tabler/icons-react";
import { cn } from "@/lib/utils";
import { formatTime } from "@/registry/new-york/player/format";
import { QUALITY_LEVELS } from "@/registry/new-york/player/quality";
import type { QualityLevel } from "@/registry/new-york/player/quality";
import type { PlayerState, PlaybackSpeed } from "@/registry/new-york/player/types";
import { YtcnProgress } from "@/registry/new-york/player/ytcn-progress";
import { YtcnVolume } from "@/registry/new-york/player/ytcn-volume";
import { YtcnQuality } from "@/registry/new-york/player/ytcn-quality";
import { YtcnFullscreen } from "@/registry/new-york/player/ytcn-fullscreen";

interface YtcnControlsProps {
  /** Full player state object */
  state: PlayerState;
  /** Toggle play/pause */
  onTogglePlay: () => void;
  /** Seek to a specific time in seconds */
  onSeek: (seconds: number) => void;
  /** Set volume (0–100) */
  onVolumeChange: (vol: number) => void;
  /** Toggle mute */
  onToggleMute: () => void;
  /** Set playback speed */
  onSpeedChange: (rate: PlaybackSpeed) => void;
  /** Set quality level */
  onQualityChange: (quality: QualityLevel | "auto") => void;
  /** Toggle fullscreen */
  onToggleFullscreen: () => void;
  /** Whether controls should be visible */
  visible: boolean;
  /**
   * Container ref for portal — ensures dropdown menus render inside the
   * player container for fullscreen visibility.
   */
  containerRef?: React.RefObject<HTMLDivElement | null>;
}

/**
 * YtcnControls — Full controls bar with progress, play/pause, volume,
 * quality/speed settings, and fullscreen toggle.
 *
 * Designed to sit at the bottom of the player container with a gradient
 * overlay. Visibility is controlled by the `visible` prop, typically
 * driven by mouse hover or drag state.
 */
export function YtcnControls({
  state,
  onTogglePlay,
  onSeek,
  onVolumeChange,
  onToggleMute,
  onSpeedChange,
  onQualityChange,
  onToggleFullscreen,
  visible,
  containerRef,
}: YtcnControlsProps) {
  return (
    <div
      className={cn(
        "absolute inset-x-0 bottom-0 z-30 flex flex-col transition-opacity duration-300",
        visible ? "opacity-100" : "pointer-events-none opacity-0"
      )}
    >
      {/* Gradient overlay */}
      <div className="pointer-events-none absolute inset-0 bg-gradient-to-t from-black/80 via-black/30 to-transparent" />

      {/* Progress bar */}
      <div className="relative z-10 px-3">
        <YtcnProgress
          currentTime={state.currentTime}
          duration={state.duration}
          loadedFraction={state.loadedFraction}
          onSeek={onSeek}
        />
      </div>

      {/* Controls row */}
      <div className="relative z-10 flex items-center gap-1 px-3 pb-2.5 pt-1.5">
        {/* Left group */}
        <div className="flex items-center gap-1">
          {/* Play/Pause */}
          <button
            onClick={(e) => {
              e.stopPropagation();
              onTogglePlay();
            }}
            className="flex items-center justify-center rounded-sm p-1.5 text-white transition-colors hover:bg-white/10"
            aria-label={state.isPlaying ? "Pause" : "Play"}
          >
            {state.isPlaying ? (
              <IconPlayerPauseFilled className="size-5" />
            ) : (
              <IconPlayerPlayFilled className="size-5" />
            )}
          </button>

          {/* Volume */}
          <YtcnVolume
            volume={state.volume}
            isMuted={state.isMuted}
            onVolumeChange={onVolumeChange}
            onToggleMute={onToggleMute}
          />

          {/* Time display */}
          <span className="ml-1.5 select-none text-xs tabular-nums text-white/80 font-mono">
            {formatTime(state.currentTime)}
            <span className="text-white/50 mx-1">/</span>
            <span className="text-white/70">{formatTime(state.duration)}</span>
          </span>
        </div>

        {/* Spacer */}
        <div className="flex-1" />

        {/* Right group */}
        <div className="flex items-center gap-0.5">
          {/* Active quality badge */}
          {state.actualQuality &&
            QUALITY_LEVELS[state.actualQuality as QualityLevel] && (
              <span className="text-xs font-semibold text-white/90 px-2 py-1 rounded bg-white/10">
                {QUALITY_LEVELS[state.actualQuality as QualityLevel].label}
              </span>
            )}

          {/* Active speed badge */}
          {state.playbackRate !== 1 && (
            <span className="text-xs font-semibold text-white/90 px-2 py-1 rounded bg-white/10">
              {state.playbackRate}x
            </span>
          )}

          {/* Settings dropdown (quality + speed) */}
          <YtcnQuality
            selectedQuality={state.selectedQuality}
            actualQuality={state.actualQuality}
            availableQualities={state.availableQualities}
            onQualityChange={onQualityChange}
            playbackRate={state.playbackRate}
            onSpeedChange={onSpeedChange}
            containerRef={containerRef}
          />

          {/* Fullscreen */}
          <YtcnFullscreen
            isFullscreen={state.isFullscreen}
            onToggle={onToggleFullscreen}
          />
        </div>
      </div>
    </div>
  );
}

"use client";

import { memo } from "react";
import { cn } from "@/lib/utils";
import { formatTime } from "@/registry/new-york/player/format";
import { useTimeline } from "@/registry/new-york/player/use-timeline";

interface YtcnProgressProps {
  /** Current playback position in seconds */
  currentTime: number;
  /** Total video duration in seconds */
  duration: number;
  /** Buffer progress as a fraction from 0 to 1 */
  loadedFraction: number;
  /** Called with the target time in seconds on click or drag */
  onSeek: (seconds: number) => void;
  className?: string;
}

/**
 * YtcnProgress — Timeline scrub bar with hover tooltip, buffer indicator,
 * and drag-to-seek.
 *
 * Memoized because it re-renders on every 250ms poll tick from the player
 * state — memo prevents unnecessary re-renders when only unrelated state
 * changes (like volume or quality) occur.
 */
export const YtcnProgress = memo(function YtcnProgress({
  currentTime,
  duration,
  loadedFraction,
  onSeek,
  className,
}: YtcnProgressProps) {
  const progress = duration > 0 ? (currentTime / duration) * 100 : 0;
  const buffered = loadedFraction * 100;

  const { barRef, isDragging, hoverTime, hoverFraction, handlers } = useTimeline({
    duration,
    onSeek,
  });

  return (
    <div
      ref={barRef}
      className={cn(
        "group/progress relative h-1 w-full cursor-pointer transition-[height] hover:h-1.5",
        className
      )}
      onMouseDown={handlers.onMouseDown}
      onMouseMove={handlers.onMouseMove}
      onMouseLeave={handlers.onMouseLeave}
      onClick={(e) => e.stopPropagation()}
      role="slider"
      aria-valuenow={Math.floor(currentTime)}
      aria-valuemin={0}
      aria-valuemax={Math.floor(duration)}
      aria-label="Video progress"
      tabIndex={0}
    >
      {/* Track background */}
      <div className="absolute inset-0 rounded-full bg-white/20" />

      {/* Buffer indicator */}
      <div
        className="absolute inset-y-0 left-0 rounded-full bg-white/30 transition-[width] duration-500"
        style={{ width: `${buffered}%` }}
      />

      {/* Filled progress */}
      <div
        className="absolute inset-y-0 left-0 rounded-full bg-primary transition-[width] duration-100"
        style={{ width: `${progress}%` }}
      />

      {/* Scrubber dot — visible on hover */}
      <div
        className="absolute top-1/2 -translate-x-1/2 -translate-y-1/2 size-3 rounded-full bg-primary border-2 border-background shadow-lg opacity-0 transition-opacity group-hover/progress:opacity-100"
        style={{ left: `${progress}%` }}
      />

      {/* Hover tooltip */}
      {hoverTime !== null && duration > 0 && (
        <div
          className="absolute -top-8 -translate-x-1/2 rounded bg-background/90 px-1.5 py-0.5 text-xs text-foreground shadow-md pointer-events-none"
          style={{
            left: `${hoverFraction * 100}%`,
          }}
        >
          {formatTime(hoverTime)}
        </div>
      )}
    </div>
  );
});

"use client";

import {
  IconVolume,
  IconVolumeOff,
  IconVolume2,
} from "@tabler/icons-react";
import { Slider } from "@/components/ui/slider";

interface YtcnVolumeProps {
  /** Current volume level (0–100) */
  volume: number;
  /** Whether audio is currently muted */
  isMuted: boolean;
  /** Called with new volume value (0–100) */
  onVolumeChange: (vol: number) => void;
  /** Toggle mute on/off */
  onToggleMute: () => void;
}

/**
 * YtcnVolume — Volume slider with mute toggle.
 *
 * The slider is hidden by default (width: 0) and expands on hover via
 * a CSS transition on the parent group. This matches YouTube's native
 * volume control UX without any JS-driven show/hide state.
 */
export function YtcnVolume({
  volume,
  isMuted,
  onVolumeChange,
  onToggleMute,
}: YtcnVolumeProps) {
  const VolumeIcon =
    isMuted || volume === 0
      ? IconVolumeOff
      : volume < 50
        ? IconVolume2
        : IconVolume;

  return (
    <div className="group/volume flex items-center gap-1">
      <button
        onClick={(e) => {
          e.stopPropagation();
          onToggleMute();
        }}
        className="flex items-center justify-center rounded-sm p-1 text-white transition-colors hover:bg-white/10"
        aria-label={isMuted ? "Unmute" : "Mute"}
      >
        <VolumeIcon className="size-5" />
      </button>
      <div className="w-0 overflow-hidden transition-[width] duration-200 group-hover/volume:w-20">
        <Slider
          value={[isMuted ? 0 : volume]}
          max={100}
          step={1}
          onValueChange={([val]) => onVolumeChange(val)}
          className="w-20 cursor-pointer"
          aria-label="Volume"
          onClick={(e) => e.stopPropagation()}
        />
      </div>
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { IconAdjustments } from "@tabler/icons-react";
import { QUALITY_LEVELS } from "@/registry/new-york/player/quality";
import type { QualityLevel } from "@/registry/new-york/player/quality";
import type { PlaybackSpeed } from "@/registry/new-york/player/types";
import { PLAYBACK_SPEEDS } from "@/registry/new-york/player/types";

interface YtcnQualityProps {
  /** The quality level the user has selected (or "auto") */
  selectedQuality: QualityLevel | "auto";
  /** The quality level YouTube is actually playing at */
  actualQuality: QualityLevel | "";
  /** Quality levels available for this video */
  availableQualities: QualityLevel[];
  /** Called when the user picks a quality level */
  onQualityChange: (quality: QualityLevel | "auto") => void;
  /** Current playback speed — displayed in the same settings dropdown */
  playbackRate?: number;
  /** Called when the user picks a speed */
  onSpeedChange?: (rate: PlaybackSpeed) => void;
  /**
   * Portal container for fullscreen visibility.
   *
   * By default Radix portals dropdown content to document.body. When the
   * player is in fullscreen mode, the browser only renders elements INSIDE
   * the fullscreen element — anything portaled to body becomes invisible.
   * Passing containerRef.current makes the portal append inside the
   * fullscreen element, keeping the dropdown always visible.
   */
  containerRef?: React.RefObject<HTMLDivElement | null>;
}

/**
 * YtcnQuality — Quality selector dropdown with optional speed picker.
 *
 * Combines quality and speed selection into a single settings dropdown,
 * portaled into the player container for fullscreen compatibility.
 */
export function YtcnQuality({
  selectedQuality,
  actualQuality,
  availableQualities,
  onQualityChange,
  playbackRate,
  onSpeedChange,
  containerRef,
}: YtcnQualityProps) {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <button
          onClick={(e) => e.stopPropagation()}
          className="flex items-center justify-center rounded-sm p-1.5 text-white transition-colors hover:bg-white/10"
          aria-label="Settings"
        >
          <IconAdjustments className="size-5" />
        </button>
      </DropdownMenuTrigger>

      <DropdownMenuContent
        align="end"
        className="w-48"
        container={containerRef?.current ?? undefined}
        onClick={(e) => e.stopPropagation()}
      >
        {/* ── Quality ── */}
        <DropdownMenuLabel>Quality</DropdownMenuLabel>

        <DropdownMenuItem
          onClick={() => onQualityChange("auto")}
          className={cn(
            "cursor-pointer",
            selectedQuality === "auto" && "bg-accent"
          )}
        >
          <span className="flex-1">Auto</span>
          {selectedQuality === "auto" && actualQuality && (
            <span className="text-xs text-muted-foreground ml-1">
              ({QUALITY_LEVELS[actualQuality as QualityLevel]?.label})
            </span>
          )}
          {selectedQuality === "auto" && (
            <span className="text-primary ml-1">✓</span>
          )}
        </DropdownMenuItem>

        {availableQualities.length === 0 ? (
          <DropdownMenuItem disabled>
            <span className="text-muted-foreground text-xs italic">
              Play video to load qualities
            </span>
          </DropdownMenuItem>
        ) : (
          availableQualities.map((quality) => (
            <DropdownMenuItem
              key={quality}
              onClick={() => onQualityChange(quality)}
              className={cn(
                "cursor-pointer",
                selectedQuality === quality && "bg-accent"
              )}
            >
              <span className="flex-1">
                {QUALITY_LEVELS[quality].label}
              </span>
              {selectedQuality === quality && (
                <span className="text-primary">✓</span>
              )}
            </DropdownMenuItem>
          ))
        )}

        {/* ── Speed (optional) ── */}
        {onSpeedChange && (
          <>
            <DropdownMenuSeparator />
            <DropdownMenuLabel>Playback Speed</DropdownMenuLabel>
            {PLAYBACK_SPEEDS.map((speed) => (
              <DropdownMenuItem
                key={speed}
                onClick={() => onSpeedChange(speed)}
                className={cn(
                  "cursor-pointer",
                  playbackRate === speed && "bg-accent"
                )}
              >
                <span className="flex-1">
                  {speed === 1 ? "Normal" : `${speed}x`}
                </span>
                {playbackRate === speed && (
                  <span className="text-primary">✓</span>
                )}
              </DropdownMenuItem>
            ))}
          </>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

"use client";

import { IconSettings } from "@tabler/icons-react";
import { cn } from "@/lib/utils";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import type { PlaybackSpeed } from "@/registry/new-york/player/types";
import { PLAYBACK_SPEEDS } from "@/registry/new-york/player/types";

interface YtcnSpeedProps {
  /** Current playback rate */
  playbackRate: number;
  /** Called with the new speed value */
  onSpeedChange: (rate: PlaybackSpeed) => void;
  /**
   * Portal container for fullscreen visibility.
   * Pass containerRef.current to ensure the popover renders inside
   * the fullscreen element rather than document.body.
   */
  containerRef?: React.RefObject<HTMLDivElement | null>;
}

/**
 * YtcnSpeed — Playback speed picker using Radix Popover.
 *
 * Portaled into the player container (via containerRef) so it remains
 * visible in fullscreen mode. Without this, the popover would be
 * appended to document.body and become invisible when the player
 * enters fullscreen.
 */
export function YtcnSpeed({
  playbackRate,
  onSpeedChange,
  containerRef,
}: YtcnSpeedProps) {
  return (
    <Popover>
      <PopoverTrigger asChild>
        <button
          className="flex items-center gap-0.5 rounded-sm px-1.5 py-1 text-xs font-medium text-white transition-colors hover:bg-white/10"
          aria-label="Playback speed"
          onClick={(e) => e.stopPropagation()}
        >
          <IconSettings className="size-4" />
          <span>{playbackRate}x</span>
        </button>
      </PopoverTrigger>
      <PopoverContent
        side="top"
        align="center"
        className="w-auto border-border/50 bg-card/95 p-1 backdrop-blur-md"
        container={containerRef?.current ?? undefined}
      >
        <div className="flex flex-col gap-0.5">
          <p className="px-2 py-1 text-xs text-muted-foreground">Speed</p>
          {PLAYBACK_SPEEDS.map((speed) => (
            <button
              key={speed}
              onClick={() => onSpeedChange(speed)}
              className={cn(
                "rounded-sm px-3 py-1.5 text-left text-sm transition-colors hover:bg-accent",
                playbackRate === speed
                  ? "bg-primary/10 font-semibold text-primary"
                  : "text-foreground"
              )}
            >
              {speed === 1 ? "Normal" : `${speed}x`}
            </button>
          ))}
        </div>
      </PopoverContent>
    </Popover>
  );
}

"use client";

import { IconMaximize, IconMinimize } from "@tabler/icons-react";

interface YtcnFullscreenProps {
  /** Whether the player is currently in fullscreen mode */
  isFullscreen: boolean;
  /** Toggle fullscreen on/off */
  onToggle: () => void;
}

/**
 * YtcnFullscreen — Fullscreen toggle button.
 *
 * Switches icon between maximize and minimize based on current state.
 */
export function YtcnFullscreen({ isFullscreen, onToggle }: YtcnFullscreenProps) {
  return (
    <button
      onClick={(e) => {
        e.stopPropagation();
        onToggle();
      }}
      className="flex items-center justify-center rounded-sm p-1.5 text-white transition-colors hover:bg-white/10"
      aria-label={isFullscreen ? "Exit fullscreen" : "Fullscreen"}
    >
      {isFullscreen ? (
        <IconMinimize className="size-5" />
      ) : (
        <IconMaximize className="size-5" />
      )}
    </button>
  );
}

"use client";

interface YtcnOverlayProps {
  /** Called when the overlay is clicked (typically toggles play/pause) */
  onClick: () => void;
}

/**
 * YtcnOverlay — Transparent click-intercept div above the iframe.
 *
 * Sits between the YouTube iframe (z-10) and the custom controls (z-30).
 * Serves two purposes:
 *   1. Captures click events for play/pause without them reaching the
 *      iframe (which has pointerEvents: none anyway, but defense in depth).
 *   2. Provides the cursor: pointer visual feedback over the video area.
 */
export function YtcnOverlay({ onClick }: YtcnOverlayProps) {
  return (
    <div
      className="absolute inset-0 z-20 cursor-pointer"
      onClick={onClick}
    />
  );
}

"use client";

import { IconLoader2 } from "@tabler/icons-react";
import { cn } from "@/lib/utils";

interface YtcnLoaderProps {
  /** Whether the loading overlay should be visible */
  isLoading: boolean;
  className?: string;
}

/**
 * YtcnLoader — Loading state overlay shown during player initialization
 * or quality-change recreation.
 *
 * Renders above the iframe but below the controls, with a backdrop blur
 * and spinner animation.
 */
export function YtcnLoader({ isLoading, className }: YtcnLoaderProps) {
  if (!isLoading) return null;

  return (
    <div
      className={cn(
        "absolute inset-0 z-10 flex flex-col items-center justify-center bg-background/90 backdrop-blur-sm",
        className
      )}
    >
      <IconLoader2 className="size-8 animate-spin text-primary mb-2" />
      <p className="text-sm text-muted-foreground">Loading video...</p>
    </div>
  );
}

import type { QualityLevel } from "@/lib/ytcn/quality";

/* ================================================================ */
/*  Playback Speed                                                   */
/* ================================================================ */

export type PlaybackSpeed = 0.25 | 0.5 | 0.75 | 1 | 1.25 | 1.5 | 1.75 | 2;

export const PLAYBACK_SPEEDS: PlaybackSpeed[] = [
  0.25, 0.5, 0.75, 1, 1.25, 1.5, 1.75, 2,
];

/* ================================================================ */
/*  Player State                                                     */
/* ================================================================ */

export interface PlayerState {
  isPlaying: boolean;
  isMuted: boolean;
  volume: number; // 0–100
  currentTime: number; // seconds
  duration: number; // seconds
  loadedFraction: number; // 0–1 buffer progress
  isLoading: boolean;
  isFullscreen: boolean;
  playbackRate: PlaybackSpeed;
  selectedQuality: QualityLevel | "auto";
  actualQuality: QualityLevel | "";
  availableQualities: QualityLevel[];
}

/* ================================================================ */
/*  Player Options                                                   */
/* ================================================================ */

export interface YtcnPlayerOptions {
  /** YouTube video ID (the 11-character string, not a full URL) */
  videoId: string;
  /** Start playback automatically. Browsers require muted audio for this. */
  autoplay?: boolean;
  /** Initial quality hint — applied via both vq and setPlaybackQualityRange */
  defaultQuality?: QualityLevel | "auto";
  /** Initial playback rate */
  defaultSpeed?: PlaybackSpeed;
  /** Resume from this timestamp (seconds) */
  startAt?: number;
  /** Fired when the video reaches its end */
  onEnd?: () => void;
  /** Polled every 250ms during playback */
  onTimeUpdate?: (currentTime: number, duration: number) => void;
  /** Fired when the actual quality level changes */
  onQualityChange?: (quality: string) => void;
  /** Fired when the playback rate changes */
  onPlaybackRateChange?: (rate: number) => void;
}

/* ================================================================ */
/*  Controls Interface                                               */
/* ================================================================ */

export interface PlayerControls {
  play: () => void;
  pause: () => void;
  togglePlay: () => void;
  seekTo: (seconds: number) => void;
  seekRelative: (delta: number) => void;
  setVolume: (vol: number) => void;
  toggleMute: () => void;
  setSpeed: (rate: PlaybackSpeed) => void;
  setQuality: (quality: QualityLevel | "auto") => void;
  toggleFullscreen: () => void;
}

/* ================================================================ */
/*  Keyboard Shortcut Bindings                                       */
/* ================================================================ */

export interface KeyboardBindings {
  play?: string;
  mute?: string;
  fullscreen?: string;
  seekBack?: string;
  seekForward?: string;
}

export const DEFAULT_KEYBOARD_BINDINGS: Required<KeyboardBindings> = {
  play: " ",
  mute: "m",
  fullscreen: "f",
  seekBack: "ArrowLeft",
  seekForward: "ArrowRight",
};

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import type {
  PlayerState,
  PlayerControls,
  PlaybackSpeed,
  YtcnPlayerOptions,
} from "@/registry/new-york/player/types";
import type { QualityLevel } from "@/registry/new-york/player/quality";
import { loadYouTubeAPI, styleIframe } from "@/registry/new-york/player/loader";
import {
  enforceQuality,
  parseAvailableQualities,
} from "@/registry/new-york/player/quality";
import { useFullscreen } from "@/registry/new-york/player/use-fullscreen";

/* ================================================================ */
/*  Initial state factory                                            */
/* ================================================================ */

function createInitialState(
  options: YtcnPlayerOptions,
  prev?: Partial<PlayerState>
): PlayerState {
  return {
    isPlaying: false,
    isMuted: prev?.isMuted ?? true,
    volume: prev?.volume ?? 100,
    currentTime: 0,
    duration: 0,
    loadedFraction: 0,
    isLoading: true,
    isFullscreen: typeof document !== "undefined" ? !!document.fullscreenElement : false,
    playbackRate: options.defaultSpeed ?? (prev?.playbackRate ?? 1),
    selectedQuality: options.defaultQuality ?? "auto",
    actualQuality: "",
    availableQualities: [],
  };
}

/* ================================================================ */
/*  useYtcnPlayer — Core player lifecycle hook                       */
/* ================================================================ */

/**
 * useYtcnPlayer — The primary hook for managing a YouTube player instance.
 *
 * Handles:
 *   - YouTube API loading (singleton)
 *   - Player creation, destruction, and recreation on quality/videoId change
 *   - State polling (currentTime, buffered, quality) every 250ms
 *   - Stale closure safety via refs for all values consumed in YT callbacks
 *   - Dual-strategy quality enforcement
 *   - Imperative controls (play, pause, seek, volume, speed, quality, fullscreen)
 *
 * Returns containerRef and playerDivRef for DOM attachment, reactive state,
 * and an imperative controls object.
 */
export function useYtcnPlayer(options: YtcnPlayerOptions) {
  const {
    videoId,
    autoplay = false,
    defaultQuality = "auto",
    defaultSpeed = 1,
    startAt = 0,
    onEnd,
    onTimeUpdate,
    onQualityChange,
    onPlaybackRateChange,
  } = options;

  // ── DOM refs ──
  const containerRef = useRef<HTMLDivElement>(null);
  const playerDivRef = useRef<HTMLDivElement>(null);
  const playerRef = useRef<YT.Player | null>(null);

  // ── Stale closure safety refs ──
  // All values consumed inside YT event callbacks (onReady, onStateChange)
  // must be stored in refs and kept in sync. Never rely on closure-captured
  // state inside YT callbacks — they fire asynchronously outside React's
  // render cycle and would capture stale values.
  const volumeRef = useRef(100);
  const isMutedRef = useRef(true);
  const playbackSpeedRef = useRef<PlaybackSpeed>(defaultSpeed);
  const selectedQualityRef = useRef<QualityLevel | "auto">(defaultQuality);

  // Callback refs — avoids re-creating the player when callbacks change
  const onEndRef = useRef(onEnd);
  const onTimeUpdateRef = useRef(onTimeUpdate);
  const onQualityChangeRef = useRef(onQualityChange);
  const onPlaybackRateChangeRef = useRef(onPlaybackRateChange);

  useEffect(() => {
    onEndRef.current = onEnd;
    onTimeUpdateRef.current = onTimeUpdate;
    onQualityChangeRef.current = onQualityChange;
    onPlaybackRateChangeRef.current = onPlaybackRateChange;
  });

  // ── State ──
  const [state, setState] = useState<PlayerState>(() =>
    createInitialState(options)
  );

  // Keep refs in sync so YT callbacks always see the latest values
  useEffect(() => {
    volumeRef.current = state.volume;
    isMutedRef.current = state.isMuted;
    playbackSpeedRef.current = state.playbackRate;
    selectedQualityRef.current = state.selectedQuality;
  }, [state.volume, state.isMuted, state.playbackRate, state.selectedQuality]);

  // ── Fullscreen ──
  const { isFullscreen, toggle: toggleFullscreen } = useFullscreen(containerRef);

  useEffect(() => {
    setState((prev) => ({ ...prev, isFullscreen }));
  }, [isFullscreen]);

  /* ----------------------------------------------------------------
   *  createPlayer
   *
   *  Destroys the current YT.Player instance and recreates it fresh.
   *  Called on initial mount and on quality changes.
   *
   *  After onReady fires we call enforceQuality() (Strategy B) to
   *  lock the quality range via the JS API — this is what makes
   *  low qualities like 360p/240p actually stick.
   * --------------------------------------------------------------- */
  const createPlayer = useCallback(
    (seekSeconds: number, quality: QualityLevel | "auto", wasPlaying: boolean) => {
      if (!videoId || !playerDivRef.current) return;

      // Update ref immediately so onReady closure reads the right value
      selectedQualityRef.current = quality;

      // Destroy existing player
      try {
        playerRef.current?.destroy();
      } catch {
        /* player may already be destroyed */
      }
      playerRef.current = null;

      // YT.Player replaces the target div with an iframe. After destroy()
      // that element is gone — inject a fresh div before each creation.
      const container = playerDivRef.current.parentElement;
      if (!container) return;
      const newDiv = document.createElement("div");
      newDiv.style.width = "100%";
      newDiv.style.height = "100%";
      container.replaceChild(newDiv, playerDivRef.current);
      (playerDivRef as React.MutableRefObject<HTMLDivElement>).current = newDiv;

      setState((prev) => ({ ...prev, isLoading: true }));

      const YT = (window as any).YT;

      // playerVars — Strategy A: vq sets the initial quality hint in the embed URL
      const playerVars: Record<string, any> = {
        controls: 0,
        modestbranding: 1,
        rel: 0,
        autoplay: wasPlaying || autoplay ? 1 : 0,
        mute: 1, // always start muted for autoplay policy; restored in onReady
        enablejsapi: 1,
        origin: window.location.origin,
        playsinline: 1,
        showinfo: 0,
        iv_load_policy: 3,
        disablekb: 0,
        fs: 0,
        cc_load_policy: 0,
        start: Math.floor(seekSeconds),
      };

      if (quality !== "auto") {
        playerVars.vq = quality;
      }

      playerRef.current = new YT.Player(newDiv, {
        videoId,
        playerVars,
        events: {
          onReady: (event: YT.PlayerEvent) => {
            const player = event.target;
            styleIframe(player);

            // Restore volume / mute / speed from refs (always fresh)
            try {
              player.setVolume(volumeRef.current);
              if (!isMutedRef.current) player.unMute();
              if (playbackSpeedRef.current !== 1) {
                player.setPlaybackRate(playbackSpeedRef.current);
              }
            } catch {
              /* player may reject these calls during initialization */
            }

            // Strategy B: lock quality range via JS API
            enforceQuality(player, selectedQualityRef.current);

            setState((prev) => ({
              ...prev,
              isLoading: false,
              duration: player.getDuration() || prev.duration,
              actualQuality:
                (player.getPlaybackQuality() as QualityLevel) || prev.actualQuality,
            }));

            if (wasPlaying) {
              try {
                player.playVideo();
              } catch {
                /* autoplay may be blocked */
              }
            }
          },

          onStateChange: (event: YT.OnStateChangeEvent) => {
            const YT = (window as any).YT;
            const player = event.target;

            switch (event.data) {
              case YT.PlayerState.PLAYING: {
                // Quality list is only available after buffering starts —
                // getAvailableQualityLevels() returns [] in onReady
                const levels: string[] = player.getAvailableQualityLevels() || [];
                const validQualities = parseAvailableQualities(levels);

                // Re-enforce quality on every PLAYING event.
                // YouTube can reset the quality lock after buffering or seeking —
                // calling it here ensures it sticks for the lifetime of playback.
                enforceQuality(player, selectedQualityRef.current);

                setState((prev) => ({
                  ...prev,
                  isPlaying: true,
                  isLoading: false,
                  duration: player.getDuration() || prev.duration,
                  actualQuality:
                    (player.getPlaybackQuality() as QualityLevel) || prev.actualQuality,
                  availableQualities:
                    validQualities.length > 0 ? validQualities : prev.availableQualities,
                }));
                break;
              }

              case YT.PlayerState.PAUSED:
                setState((prev) => ({ ...prev, isPlaying: false }));
                break;

              case YT.PlayerState.BUFFERING:
                setState((prev) => ({ ...prev, isLoading: true }));
                break;

              case YT.PlayerState.ENDED:
                setState((prev) => ({ ...prev, isPlaying: false }));
                onEndRef.current?.();
                break;
            }
          },

          onPlaybackQualityChange: (event: YT.OnPlaybackQualityChangeEvent) => {
            setState((prev) => ({
              ...prev,
              actualQuality: event.data as QualityLevel,
            }));
            onQualityChangeRef.current?.(event.data);
          },

          onPlaybackRateChange: (event: any) => {
            const rate = event.data as PlaybackSpeed;
            setState((prev) => ({ ...prev, playbackRate: rate }));
            onPlaybackRateChangeRef.current?.(rate);
          },

          onError: () => {
            setState((prev) => ({ ...prev, isLoading: false }));
          },
        },
      });
    },
    [videoId, autoplay]
  );

  /* ---- Initialize player on videoId change ---- */
  useEffect(() => {
    if (!videoId) return;

    let isCancelled = false;

    const init = async () => {
      await loadYouTubeAPI();
      if (isCancelled) return;

      setState((prev) => createInitialState(options, prev));
      createPlayer(startAt, defaultQuality, autoplay);
    };

    init();

    return () => {
      isCancelled = true;
      try {
        playerRef.current?.destroy();
      } catch {
        /* player may already be gone */
      }
      playerRef.current = null;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [videoId]);

  /* ---- Poll for currentTime / buffered / quality ---- */
  useEffect(() => {
    const interval = setInterval(() => {
      const player = playerRef.current;
      if (!player?.getCurrentTime) return;
      try {
        const currentTime = player.getCurrentTime();
        const duration = player.getDuration();
        const loadedFraction = player.getVideoLoadedFraction();

        setState((prev) => ({
          ...prev,
          currentTime,
          duration: duration > 0 ? duration : prev.duration,
          loadedFraction,
        }));

        onTimeUpdateRef.current?.(currentTime, duration);
      } catch {
        /* player may be in a destroyed state between intervals */
      }
    }, 250);

    return () => clearInterval(interval);
  }, []);

  /* ================================================================ */
  /*  Controls — imperative methods exposed to consumers              */
  /* ================================================================ */

  const play = useCallback(() => {
    try {
      playerRef.current?.playVideo();
    } catch {
      /* noop */
    }
  }, []);

  const pause = useCallback(() => {
    try {
      playerRef.current?.pauseVideo();
    } catch {
      /* noop */
    }
  }, []);

  const togglePlay = useCallback(() => {
    const player = playerRef.current;
    if (!player) return;
    try {
      const YT = (window as any).YT;
      if (player.getPlayerState() === YT.PlayerState.PLAYING) {
        player.pauseVideo();
      } else {
        player.playVideo();
      }
    } catch {
      /* noop */
    }
  }, []);

  const seekTo = useCallback((seconds: number) => {
    const player = playerRef.current;
    if (!player) return;
    try {
      player.seekTo(seconds, true);
      setState((prev) => ({ ...prev, currentTime: seconds }));
    } catch {
      /* noop */
    }
  }, []);

  const seekRelative = useCallback((delta: number) => {
    const player = playerRef.current;
    if (!player) return;
    try {
      const current = player.getCurrentTime();
      const duration = player.getDuration();
      const newTime = Math.max(0, Math.min(duration, current + delta));
      player.seekTo(newTime, true);
      setState((prev) => ({ ...prev, currentTime: newTime }));
    } catch {
      /* noop */
    }
  }, []);

  const setVolume = useCallback((vol: number) => {
    const player = playerRef.current;
    if (!player) return;
    try {
      player.setVolume(vol);
      if (vol > 0) {
        player.unMute();
        isMutedRef.current = false;
      } else {
        player.mute();
        isMutedRef.current = true;
      }
      volumeRef.current = vol;
      setState((prev) => ({ ...prev, volume: vol, isMuted: vol === 0 }));
    } catch {
      /* noop */
    }
  }, []);

  const toggleMute = useCallback(() => {
    const player = playerRef.current;
    if (!player) return;
    try {
      if (isMutedRef.current) {
        player.unMute();
        isMutedRef.current = false;
        setState((prev) => ({ ...prev, isMuted: false }));
      } else {
        player.mute();
        isMutedRef.current = true;
        setState((prev) => ({ ...prev, isMuted: true }));
      }
    } catch {
      /* noop */
    }
  }, []);

  const setSpeed = useCallback((rate: PlaybackSpeed) => {
    const player = playerRef.current;
    if (!player) return;
    try {
      player.setPlaybackRate(rate);
      playbackSpeedRef.current = rate;
      setState((prev) => ({ ...prev, playbackRate: rate }));
    } catch {
      /* noop */
    }
  }, []);

  /**
   * setQuality — Changes quality by destroying and recreating the player.
   *
   * YouTube's IFrame API does not reliably apply quality changes to an
   * already-running player. Mid-session setPlaybackQuality() calls are
   * frequently ignored, especially for low qualities. The reliable fix
   * is full player destruction + recreation.
   *
   * Captures currentTime and isPlaying state before destroying, then
   * restores them in the new player's onReady callback.
   */
  const setQuality = useCallback(
    (quality: QualityLevel | "auto") => {
      const player = playerRef.current;
      if (!player || !videoId) return;

      let currentTime = 0;
      let wasPlaying = false;

      try {
        currentTime = player.getCurrentTime() || 0;
        const YT = (window as any).YT;
        wasPlaying = player.getPlayerState() === YT.PlayerState.PLAYING;
      } catch {
        /* noop */
      }

      setState((prev) => ({ ...prev, selectedQuality: quality }));
      createPlayer(currentTime, quality, wasPlaying);
    },
    [videoId, createPlayer]
  );

  // ── Compose controls object ──
  const controls: PlayerControls = {
    play,
    pause,
    togglePlay,
    seekTo,
    seekRelative,
    setVolume,
    toggleMute,
    setSpeed,
    setQuality,
    toggleFullscreen,
  };

  return {
    playerRef,
    containerRef,
    playerDivRef,
    state,
    controls,
  };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

/**
 * useFullscreen — Abstracts the Fullscreen API for a given container ref.
 *
 * Listens for `fullscreenchange` events on `document` rather than the
 * element itself, because the event bubbles and the spec guarantees it
 * fires on `document`. This avoids issues with vendor-prefixed events
 * on older browsers.
 *
 * Returns:
 *   - isFullscreen: whether the element is currently fullscreen
 *   - toggle: call to enter/exit fullscreen
 *   - enter / exit: explicit directional methods
 */
export function useFullscreen(containerRef: React.RefObject<HTMLDivElement | null>) {
  const [isFullscreen, setIsFullscreen] = useState(false);
  const mounted = useRef(true);

  useEffect(() => {
    mounted.current = true;

    const handleChange = () => {
      if (mounted.current) {
        setIsFullscreen(!!document.fullscreenElement);
      }
    };

    document.addEventListener("fullscreenchange", handleChange);
    return () => {
      mounted.current = false;
      document.removeEventListener("fullscreenchange", handleChange);
    };
  }, []);

  const enter = useCallback(() => {
    try {
      containerRef.current?.requestFullscreen();
    } catch {
      /* fullscreen may be denied by browser policy */
    }
  }, [containerRef]);

  const exit = useCallback(() => {
    try {
      if (document.fullscreenElement) document.exitFullscreen();
    } catch {
      /* exit can throw if not in fullscreen */
    }
  }, []);

  const toggle = useCallback(() => {
    if (document.fullscreenElement) {
      exit();
    } else {
      enter();
    }
  }, [enter, exit]);

  return { isFullscreen, toggle, enter, exit };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

interface UseTimelineOptions {
  /** Total video duration in seconds */
  duration: number;
  /** Called with the target time in seconds on click or drag */
  onSeek: (seconds: number) => void;
}

interface UseTimelineReturn {
  barRef: React.RefObject<HTMLDivElement | null>;
  isDragging: boolean;
  hoverTime: number | null;
  hoverFraction: number;
  handlers: {
    onMouseDown: (e: React.MouseEvent) => void;
    onMouseMove: (e: React.MouseEvent) => void;
    onMouseLeave: () => void;
  };
}

/**
 * useTimeline — Manages progress bar interaction state.
 *
 * Handles hover position tracking, drag-to-seek with window-level
 * mousemove/mouseup listeners (so dragging works even when cursor leaves
 * the bar), and converts pixel positions to time values.
 *
 * Returns a barRef to attach to the progress bar container, reactive
 * state (isDragging, hoverTime), and event handlers.
 */
export function useTimeline({ duration, onSeek }: UseTimelineOptions): UseTimelineReturn {
  const barRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [hoverTime, setHoverTime] = useState<number | null>(null);
  const [hoverFraction, setHoverFraction] = useState(0);

  const getTimeFromPosition = useCallback(
    (clientX: number): number => {
      const bar = barRef.current;
      if (!bar || duration <= 0) return 0;
      const rect = bar.getBoundingClientRect();
      const ratio = Math.max(0, Math.min(1, (clientX - rect.left) / rect.width));
      return ratio * duration;
    },
    [duration]
  );

  const getFractionFromPosition = useCallback(
    (clientX: number): number => {
      const bar = barRef.current;
      if (!bar) return 0;
      const rect = bar.getBoundingClientRect();
      return Math.max(0, Math.min(1, (clientX - rect.left) / rect.width));
    },
    []
  );

  const onMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();
      setIsDragging(true);
      const time = getTimeFromPosition(e.clientX);
      const fraction = getFractionFromPosition(e.clientX);
      setHoverFraction(fraction);
      onSeek(time);
    },
    [getTimeFromPosition, getFractionFromPosition, onSeek]
  );

  const onMouseMove = useCallback(
    (e: React.MouseEvent) => {
      const time = getTimeFromPosition(e.clientX);
      const fraction = getFractionFromPosition(e.clientX);
      setHoverTime(time);
      setHoverFraction(fraction);
      if (isDragging) {
        onSeek(time);
      }
    },
    [getTimeFromPosition, getFractionFromPosition, isDragging, onSeek]
  );

  const onMouseLeave = useCallback(() => {
    if (!isDragging) {
      setHoverTime(null);
    }
  }, [isDragging]);

  // Window-level listeners for drag continuation outside the bar
  useEffect(() => {
    if (!isDragging) return;

    const handleMove = (e: MouseEvent) => {
      const time = getTimeFromPosition(e.clientX);
      const fraction = getFractionFromPosition(e.clientX);
      setHoverTime(time);
      setHoverFraction(fraction);
      onSeek(time);
    };

    const handleUp = () => {
      setIsDragging(false);
      setHoverTime(null);
    };

    window.addEventListener("mousemove", handleMove);
    window.addEventListener("mouseup", handleUp);
    return () => {
      window.removeEventListener("mousemove", handleMove);
      window.removeEventListener("mouseup", handleUp);
    };
  }, [isDragging, getTimeFromPosition, getFractionFromPosition, onSeek]);

  return {
    barRef,
    isDragging,
    hoverTime,
    hoverFraction,
    handlers: {
      onMouseDown,
      onMouseMove,
      onMouseLeave,
    },
  };
}

"use client";

import { useEffect } from "react";
import type { KeyboardBindings } from "@/registry/new-york/player/types";
import { DEFAULT_KEYBOARD_BINDINGS } from "@/registry/new-york/player/types";

interface UseKeyboardShortcutsOptions {
  /** Master toggle — set to false to disable all shortcuts */
  enabled: boolean;
  onPlay?: () => void;
  onMute?: () => void;
  onFullscreen?: () => void;
  onSeekBack?: () => void;
  onSeekForward?: () => void;
  /** Override default key bindings */
  bindings?: KeyboardBindings;
}

/**
 * useKeyboardShortcuts — Global keyboard listener for player controls.
 *
 * Attaches to `window` so shortcuts work regardless of focus. Skips
 * events when the active element is an <input>, <textarea>, or any
 * element with [contenteditable], to avoid hijacking text input.
 *
 * Bindings are configurable via the `bindings` prop. Defaults match
 * YouTube's native shortcuts (Space, F, M, ←, →).
 */
export function useKeyboardShortcuts({
  enabled,
  onPlay,
  onMute,
  onFullscreen,
  onSeekBack,
  onSeekForward,
  bindings: customBindings,
}: UseKeyboardShortcutsOptions): void {
  useEffect(() => {
    if (!enabled) return;

    const bindings = { ...DEFAULT_KEYBOARD_BINDINGS, ...customBindings };

    const handleKeyDown = (e: KeyboardEvent) => {
      // Skip when user is typing in an input field
      const target = e.target as HTMLElement;
      if (
        target instanceof HTMLInputElement ||
        target instanceof HTMLTextAreaElement ||
        target.isContentEditable
      ) {
        return;
      }

      const key = e.key;

      if (key === bindings.play) {
        e.preventDefault();
        onPlay?.();
      } else if (key.toLowerCase() === bindings.mute?.toLowerCase()) {
        onMute?.();
      } else if (key.toLowerCase() === bindings.fullscreen?.toLowerCase()) {
        onFullscreen?.();
      } else if (key === bindings.seekBack) {
        onSeekBack?.();
      } else if (key === bindings.seekForward) {
        onSeekForward?.();
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [enabled, onPlay, onMute, onFullscreen, onSeekBack, onSeekForward, customBindings]);
}

"use client";

import { useEffect, useRef, useState } from "react";
import { loadYouTubeAPI } from "@/registry/new-york/player/loader";

/**
 * useYouTubeAPI — Loads the YouTube IFrame API once, shared across all players.
 *
 * Uses a module-level singleton promise internally (via loadYouTubeAPI) to
 * ensure exactly one <script> tag is injected regardless of how many
 * components call this hook.
 *
 * Returns { isReady: true } once `YT.Player` is available on `window`.
 */
export function useYouTubeAPI() {
  const [isReady, setIsReady] = useState(false);
  const mounted = useRef(true);

  useEffect(() => {
    mounted.current = true;

    loadYouTubeAPI().then(() => {
      if (mounted.current) setIsReady(true);
    });

    return () => {
      mounted.current = false;
    };
  }, []);

  return { isReady };
}

/**
 * loadYouTubeAPI — Singleton YouTube IFrame API loader.
 *
 * Idempotent: multiple calls from different components share a single script
 * load and a single global `onYouTubeIframeAPIReady` callback. Returns a
 * promise that resolves once `YT.Player` is available on window.
 *
 * SSR-safe: guards all `window` access behind a typeof check. In SSR
 * environments (Next.js App Router, Remix, etc.) this returns a resolved
 * promise that does nothing.
 */

let ytApiPromise: Promise<void> | null = null;

export function loadYouTubeAPI(): Promise<void> {
  // SSR guard — no window in server environments
  if (typeof window === "undefined") return Promise.resolve();

  // Already loaded (e.g. user included the script manually)
  if ((window as any).YT?.Player) return Promise.resolve();

  // Singleton: return existing promise if we've already started loading
  if (ytApiPromise) return ytApiPromise;

  ytApiPromise = new Promise<void>((resolve) => {
    (window as any).onYouTubeIframeAPIReady = () => resolve();
    const script = document.createElement("script");
    script.src = "https://www.youtube.com/iframe_api";
    document.head.appendChild(script);
  });

  return ytApiPromise;
}

/**
 * styleIframe — Offsets the YouTube iframe to crop native chrome.
 *
 * YouTube renders its own controls bar (~60px tall) at the bottom of the
 * iframe. Since the iframe is cross-origin, we can't remove these via CSS
 * inside the iframe. Instead we push the iframe 60px above its container
 * and add 120px to its total height, effectively cropping the native bar
 * out of the visible area.
 *
 * The slight horizontal overflow (102% width, -1% left) accounts for
 * YouTube's thin side borders on some resolutions.
 *
 * `pointerEvents: none` ensures any remaining clickable YouTube chrome
 * is blocked — our overlay div handles all user interaction instead.
 */
export function styleIframe(player: YT.Player): void {
  try {
    const iframe = player.getIframe();
    if (iframe) {
      iframe.style.pointerEvents = "none";
      iframe.style.position = "absolute";
      iframe.style.top = "-60px";
      iframe.style.left = "-1%";
      iframe.style.width = "102%";
      iframe.style.height = "calc(100% + 120px)";
    }
  } catch {
    /* player may be in a destroyed state */
  }
}

/**
 * QUALITY_LEVELS — YouTube quality level identifiers mapped to human labels.
 *
 * The `order` field defines sort priority: 0 = highest quality, 7 = lowest.
 * These string keys are the exact values YouTube's IFrame API returns from
 * `getAvailableQualityLevels()` and accepts in `setPlaybackQuality()`.
 */
export const QUALITY_LEVELS = {
  highres: { label: "4K+", order: 0 },
  hd2160: { label: "4K", order: 1 },
  hd1440: { label: "1440p", order: 2 },
  hd1080: { label: "1080p", order: 3 },
  hd720: { label: "720p", order: 4 },
  large: { label: "480p", order: 5 },
  medium: { label: "360p", order: 6 },
  small: { label: "240p", order: 7 },
} as const;

export type QualityLevel = keyof typeof QUALITY_LEVELS;

/**
 * enforceQuality — Dual-strategy quality enforcement.
 *
 * Strategy B (JS API lock): Called after onReady AND on every PLAYING state
 * change. Sets both min and max quality to the same level, forcing YouTube
 * to stay within that exact range. This is what makes lower qualities like
 * 360p/240p actually stick — the vq playerVar (Strategy A, applied at player
 * creation time) alone is not enough for low qualities because YouTube may
 * silently upgrade them if it detects a fast connection.
 *
 * To release the lock and return to adaptive streaming, we set the range
 * from "small" to "highres" which allows YouTube full freedom.
 *
 * Strategy A (vq playerVar) is applied separately at player creation time
 * in the loader — see use-ytcn-player.ts for that path.
 */
export function enforceQuality(
  player: YT.Player | null,
  quality: QualityLevel | "auto"
): void {
  if (!player) return;
  try {
    if (quality === "auto") {
      // Release the quality lock — let YouTube choose freely
      if (typeof (player as any).setPlaybackQualityRange === "function") {
        (player as any).setPlaybackQualityRange("small", "highres");
      }
    } else {
      // Lock both min and max to the same level
      if (typeof (player as any).setPlaybackQualityRange === "function") {
        (player as any).setPlaybackQualityRange(quality, quality);
      }
      // Fallback: also call the single-quality setter if available
      if (typeof (player as any).setPlaybackQuality === "function") {
        (player as any).setPlaybackQuality(quality);
      }
    }
  } catch {
    /* YouTube API calls can throw if the player is in a bad state */
  }
}

/**
 * Filters and sorts raw quality strings from getAvailableQualityLevels()
 * into typed, ordered QualityLevel values.
 */
export function parseAvailableQualities(levels: string[]): QualityLevel[] {
  return levels
    .filter((q): q is QualityLevel => q in QUALITY_LEVELS)
    .sort((a, b) => QUALITY_LEVELS[a].order - QUALITY_LEVELS[b].order);
}

/**
 * formatTime — Converts seconds to a human-readable timestamp string.
 *
 * Returns "H:MM:SS" for videos ≥ 1 hour, "M:SS" otherwise.
 * Handles edge cases: negative values, NaN, Infinity all return "0:00".
 */
export function formatTime(seconds: number): string {
  if (!isFinite(seconds) || seconds < 0) return "0:00";
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  const s = Math.floor(seconds % 60);
  if (h > 0) {
    return `${h}:${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`;
  }
  return `${m}:${String(s).padStart(2, "0")}`;
}
